import {
  Component, OnInit, OnDestroy,
  ViewChild, ElementRef, NgZone,
  ChangeDetectionStrategy, ChangeDetectorRef
} from '@angular/core';
import { Subject, combineLatest, debounceTime, distinctUntilChanged, takeUntil } from 'rxjs';
import { FormControl } from '@angular/forms';
import { UserService, RoleDistribution } from '../../services/user.service';
import { User } from '../../models/user.model';

@Component({
  selector: 'app-user-dashboard',
  templateUrl: './user-dashboard.component.html',
  styleUrls: ['./user-dashboard.component.scss'],
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class UserDashboardComponent implements OnInit, OnDestroy {
  @ViewChild('chartCanvas') chartCanvas!: ElementRef<HTMLCanvasElement>;

  users: User[] = [];
  filteredUsers: User[] = [];
  showModal = false;
  isLoadingModal = false;
  isLoadingChart = false;
  chartReady = false;

  // Pagination
  currentPage = 1;
  pageSize = 5;
  searchControl = new FormControl('');

  // Sorting
  sortColumn: keyof User | '' = '';
  sortAsc = true;

  private chart: any = null;
  private destroy$ = new Subject<void>();
  private searchTerm = '';

  constructor(
    private userService: UserService,
    private ngZone: NgZone,
    private cdr: ChangeDetectorRef
  ) {}

  ngOnInit(): void {
    // Subscribe to user list changes
    this.userService.users$
      .pipe(takeUntil(this.destroy$))
      .subscribe(users => {
        this.users = users;
        this.applyFilter();
        this.cdr.markForCheck();
      });

    // Debounced search
    this.searchControl.valueChanges.pipe(
      debounceTime(300),
      distinctUntilChanged(),
      takeUntil(this.destroy$)
    ).subscribe(term => {
      this.searchTerm = term ?? '';
      this.currentPage = 1;
      this.applyFilter();
      this.cdr.markForCheck();
    });

    // Subscribe to role distribution for chart updates
    this.userService.roleDistribution$
      .pipe(takeUntil(this.destroy$))
      .subscribe(dist => {
        if (this.chart) {
          this.updateChart(dist);
        }
      });

    // Load chart lazily
    this.loadChart();
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
    this.chart?.destroy();
  }

  // ── Chart ─────────────────────────────────────────────────────────────────

  private async loadChart(): Promise<void> {
    this.isLoadingChart = true;
    this.cdr.markForCheck();

    try {
      // Lazy-load Chart.js
      const { Chart, ArcElement, Tooltip, Legend, PieController } = await import('chart.js');
      Chart.register(ArcElement, Tooltip, Legend, PieController);

      // Wait for ViewChild to be ready
      await this.waitForCanvas();

      this.ngZone.runOutsideAngular(() => {
        const dist = this.currentDistribution();
        this.chart = new Chart(this.chartCanvas.nativeElement, {
          type: 'pie',
          data: this.buildChartData(dist),
          options: {
            responsive: true,
            maintainAspectRatio: false,
            animation: { duration: 600, easing: 'easeInOutQuart' },
            plugins: {
              legend: {
                position: 'bottom',
                labels: {
                  font: { family: 'DM Sans', size: 13, weight: 500 },
                  color: '#383838',
                  padding: 20,
                  usePointStyle: true,
                  pointStyleWidth: 12
                }
              },
              tooltip: {
                callbacks: {
                  label: (ctx: any) => {
                    const total = (ctx.dataset.data as number[]).reduce((a: number, b: number) => a + b, 0);
                    const pct = total > 0 ? Math.round((ctx.parsed / total) * 100) : 0;
                    return ` ${ctx.label}: ${ctx.parsed} (${pct}%)`;
                  }
                },
                backgroundColor: '#383838',
                titleFont: { family: 'DM Sans', size: 13 },
                bodyFont: { family: 'DM Sans', size: 13 },
                padding: 12,
                cornerRadius: 8
              }
            }
          }
        });
      });

      this.chartReady = true;
    } catch (err) {
      console.error('Chart.js failed to load:', err);
    } finally {
      this.isLoadingChart = false;
      this.cdr.markForCheck();
    }
  }

  private waitForCanvas(): Promise<void> {
    return new Promise(resolve => {
      const check = () => {
        if (this.chartCanvas?.nativeElement) {
          resolve();
        } else {
          setTimeout(check, 50);
        }
      };
      setTimeout(check, 0);
    });
  }

  private buildChartData(dist: RoleDistribution) {
    return {
      labels: ['Admin', 'Editor', 'Viewer'],
      datasets: [{
        data: [dist.Admin, dist.Editor, dist.Viewer],
        backgroundColor: ['#1c4980', '#0891b2', '#7c3aed'],
        hoverBackgroundColor: ['#163a66', '#0c7a9e', '#6d28d9'],
        borderWidth: 3,
        borderColor: '#ffffff',
        hoverBorderWidth: 3
      }]
    };
  }

  private updateChart(dist: RoleDistribution): void {
    if (!this.chart) return;
    this.ngZone.runOutsideAngular(() => {
      this.chart.data.datasets[0].data = [dist.Admin, dist.Editor, dist.Viewer];
      this.chart.update('active');
    });
  }

  private currentDistribution(): RoleDistribution {
    return {
      Admin: this.users.filter(u => u.role === 'Admin').length,
      Editor: this.users.filter(u => u.role === 'Editor').length,
      Viewer: this.users.filter(u => u.role === 'Viewer').length
    };
  }

  // ── Table & Filtering ─────────────────────────────────────────────────────

  applyFilter(): void {
    let result = [...this.users];
    if (this.searchTerm) {
      const q = this.searchTerm.toLowerCase();
      result = result.filter(u =>
        u.name.toLowerCase().includes(q) ||
        u.email.toLowerCase().includes(q) ||
        u.role.toLowerCase().includes(q)
      );
    }
    if (this.sortColumn) {
      result.sort((a, b) => {
        const aVal = String(a[this.sortColumn as keyof User]);
        const bVal = String(b[this.sortColumn as keyof User]);
        return this.sortAsc ? aVal.localeCompare(bVal) : bVal.localeCompare(aVal);
      });
    }
    this.filteredUsers = result;
  }

  sort(col: keyof User): void {
    if (this.sortColumn === col) {
      this.sortAsc = !this.sortAsc;
    } else {
      this.sortColumn = col;
      this.sortAsc = true;
    }
    this.applyFilter();
  }

  get totalPages(): number {
    return Math.max(1, Math.ceil(this.filteredUsers.length / this.pageSize));
  }

  get pagedUsers(): User[] {
    const start = (this.currentPage - 1) * this.pageSize;
    return this.filteredUsers.slice(start, start + this.pageSize);
  }

  get pages(): number[] {
    return Array.from({ length: this.totalPages }, (_, i) => i + 1);
  }

  goToPage(page: number): void {
    if (page >= 1 && page <= this.totalPages) {
      this.currentPage = page;
    }
  }

  deleteUser(id: string): void {
    this.userService.deleteUser(id);
    if (this.currentPage > this.totalPages) {
      this.currentPage = this.totalPages;
    }
  }

  // ── Modal ─────────────────────────────────────────────────────────────────

  async openModal(): Promise<void> {
    this.isLoadingModal = true;
    this.cdr.markForCheck();

    // Simulate lazy-load delay to show spinner
    await new Promise(r => setTimeout(r, 300));

    this.showModal = true;
    this.isLoadingModal = false;
    this.cdr.markForCheck();
  }

  closeModal(): void {
    this.showModal = false;
    this.cdr.markForCheck();
  }

  onUserAdded(user: { name: string; email: string; role: any }): void {
    this.userService.addUser(user);
    this.closeModal();
    this.currentPage = this.totalPages; // Jump to last page to show new user
  }

  trackByUserId(_: number, user: User): string {
    return user.id;
  }
}
<div class="dashboard">
  <header class="dashboard__header">
    <div class="header__brand">
      <span class="brand-icon">⬡</span>
      <div>
        <h1 class="brand-title">UserBoard</h1>
        <p class="brand-sub">Manage your team members</p>
      </div>
    </div>
    <button class="btn btn--primary" (click)="openModal()" [disabled]="isLoadingModal">
      <span class="btn__loader" *ngIf="isLoadingModal"></span>
      <span *ngIf="!isLoadingModal">
        <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" style="vertical-align:-3px;margin-right:6px">
          <line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/>
        </svg>
        Add User
      </span>
    </button>
  </header>

  <div class="stats-bar">
    <div class="stat-card">
      <div class="stat-card__value">{{ users.length }}</div>
      <div class="stat-card__label">Total Users</div>
    </div>
    <div class="stat-card stat-card--admin">
      <div class="stat-card__value">{{ users | roleCount:'Admin' }}</div>
      <div class="stat-card__label">Admins</div>
    </div>
    <div class="stat-card stat-card--editor">
      <div class="stat-card__value">{{ users | roleCount:'Editor' }}</div>
      <div class="stat-card__label">Editors</div>
    </div>
    <div class="stat-card stat-card--viewer">
      <div class="stat-card__value">{{ users | roleCount:'Viewer' }}</div>
      <div class="stat-card__label">Viewers</div>
    </div>
  </div>

  <div class="dashboard__content">
    <section class="panel panel--table">
      <div class="panel__head">
        <h2 class="panel__title">Team Members</h2>
        <div class="search-box">
          <svg class="search-box__icon" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
            <circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/>
          </svg>
          <input
            class="search-box__input"
            type="text"
            placeholder="Search users..."
            [formControl]="searchControl"
          />
        </div>
      </div>

      <div class="table-wrap">
        <table class="users-table">
          <thead>
            <tr>
              <th class="sortable" (click)="sort('name')">
                Name
                <span class="sort-icon" [class.sort-icon--asc]="sortColumn === 'name' && sortAsc"
                      [class.sort-icon--active]="sortColumn === 'name'">↕</span>
              </th>
              <th class="sortable" (click)="sort('email')">
                Email
                <span class="sort-icon" [class.sort-icon--asc]="sortColumn === 'email' && sortAsc"
                      [class.sort-icon--active]="sortColumn === 'email'">↕</span>
              </th>
              <th class="sortable" (click)="sort('role')">
                Role
                <span class="sort-icon" [class.sort-icon--asc]="sortColumn === 'role' && sortAsc"
                      [class.sort-icon--active]="sortColumn === 'role'">↕</span>
              </th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            <tr *ngFor="let user of pagedUsers; trackBy: trackByUserId" class="table-row">
              <td>
                <div class="user-cell">
                  <div class="user-avatar" [style.background]="user.role === 'Admin' ? '#1c4980' : user.role === 'Editor' ? '#0891b2' : '#7c3aed'">
                    {{ user.name.charAt(0) }}
                  </div>
                  <span class="user-name">{{ user.name }}</span>
                </div>
              </td>
              <td class="cell--email">{{ user.email }}</td>
              <td>
                <span class="badge" [ngClass]="'badge--' + user.role.toLowerCase()">
                  {{ user.role }}
                </span>
              </td>
              <td>
                <button class="btn-icon btn-icon--danger" (click)="deleteUser(user.id)" title="Remove user">
                  <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                    <polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"/>
                    <path d="M10 11v6"/><path d="M14 11v6"/>
                  </svg>
                </button>
              </td>
            </tr>
            <tr *ngIf="pagedUsers.length === 0">
              <td colspan="4" class="table-empty">
                <div class="empty-state">
                  <span class="empty-state__icon">👥</span>
                  <p>No users found</p>
                </div>
              </td>
            </tr>
          </tbody>
        </table>
      </div>

      <div class="pagination" *ngIf="totalPages > 1">
        <button class="page-btn" (click)="goToPage(currentPage - 1)" [disabled]="currentPage === 1">‹</button>
        <button
          class="page-btn"
          *ngFor="let p of pages"
          [class.page-btn--active]="p === currentPage"
          (click)="goToPage(p)"
        >{{ p }}</button>
        <button class="page-btn" (click)="goToPage(currentPage + 1)" [disabled]="currentPage === totalPages">›</button>
        <span class="pagination__info">{{ filteredUsers.length }} users</span>
      </div>
    </section>

    <section class="panel panel--chart">
      <h2 class="panel__title">Role Distribution</h2>

      <div class="chart-container" [class.chart-container--loading]="isLoadingChart">
        <div *ngIf="isLoadingChart" class="chart-skeleton">
          <div class="skeleton-circle"></div>
          <div class="skeleton-legend">
            <div class="skeleton-line" *ngFor="let i of [1,2,3]"></div>
          </div>
        </div>
        <canvas #chartCanvas [style.display]="isLoadingChart ? 'none' : 'block'"></canvas>
      </div>

      <div class="role-list" *ngIf="!isLoadingChart">
        <div class="role-item" *ngFor="let r of ['Admin','Editor','Viewer']">
          <span class="role-dot" [ngClass]="'role-dot--' + r.toLowerCase()"></span>
          <span class="role-label">{{ r }}</span>
          <span class="role-count">{{ users | roleCount:r }}</span>
        </div>
      </div>
    </section>

  </div>

  <div class="modal-backdrop" *ngIf="showModal" (click)="closeModal()">
    <div class="modal" (click)="$event.stopPropagation()">
      <app-user-form
        (userAdded)="onUserAdded($event)"
        (cancelled)="closeModal()"
      ></app-user-form>
    </div>
  </div>

</div><!-- /.dashboard -->
